INSERT INTO feed_articles
  (slug, title, summary, content, category, cover_url, source_kind, source_name, author_display_name, status, tags, reading_time_min, views, likes, published_at, created_at, source_language)
VALUES (
  'ii-nastavnik-uchispro-pochti-kak-zhivoy-repetitor',
  'ИИ-наставник УЧИСЬПРО: мы максимально приблизились к живому репетитору',
  'Новые супер-курсы по физике, математике и информатике говорят голосом, ведут урок пошагово и видят пробелы ученика. Рассказываем, что обновилось и почему это уже почти как занятие с человеком — при всём уважении к учителям.',
  E'Хорошего репетитора ничто не заменит — это правда. Живой учитель чувствует настроение ребёнка, вдохновляет личным примером и радуется его победам как своим. Мы глубоко уважаем труд педагогов и не спорим с этим. Но у живого репетитора есть и объективные ограничения: он не может заниматься с учеником в три часа ночи перед экзаменом, стоит дорого и физически не успевает ко всем. Именно здесь на помощь приходит наш ИИ-наставник — не вместо учителя, а рядом с ним.\n\nЗа последнее время мы серьёзно прокачали платформу, и сегодня хотим честно показать, что изменилось.\n\nГолос вместо стены текста. Теперь наставник Дмитрий и его коллеги разговаривают вслух — спокойным человеческим голосом. Ученик может просто слушать объяснение, как на настоящем уроке, и отвечать голосом в микрофон. Это особенно важно для младших школьников, которые ещё неуверенно читают, и для взрослых, которым тяжело подолгу смотреть в экран. Скорость речи и размер текста настраиваются под себя.\n\nНе ответы, а урок. Раньше ИИ просто отвечал на вопрос. Теперь он ведёт занятие как репетитор: сначала объясняет суть простыми словами и примером из жизни, потом — главную идею, а в конце проверяет, понял ли ученик, и задаёт встречный вопрос. Это диалог, а не справочник.\n\nПрограммы уровня сильной школы. Мы пересобрали супер-курсы по физике, математике и информатике так, чтобы они покрывали всю школьную программу и шли дальше — к профильному ЕГЭ и вступительным испытаниям технических вузов. В физике это полсотни уроков: от кинематики и законов Ньютона до квантовой и ядерной физики. В математике — тригонометрия, логарифмы, производные, стереометрия, задачи с параметром. В информатике — алгоритмы, Python и разбор самых сложных заданий ЕГЭ.\n\nДиагностика перед стартом. Ученик отвечает на пять коротких вопросов, и наставник честно показывает, где есть пробелы, и предлагает раздел, с которого стоит начать. Никакой воды — сразу по делу.\n\nВидимый рост знаний. Теперь на экране видно, как растёт шкала знаний по предмету. Пройденные уроки отмечаются галочками, заполняются прогресс-бары разделов. Ребёнок видит свой прогресс — и это мотивирует не хуже похвалы учителя.\n\nПочему это уже почти как человек? Потому что наставник доступен круглосуточно и бесконечно терпелив. Он никогда не торопит, не раздражается и готов объяснить одно и то же десять раз разными словами. Он помнит контекст разговора и подстраивается под темп ученика. Конечно, он не заменит тёплых отношений с любимым учителем — да мы и не ставим такой цели. Наша задача в другом: сделать качественную подготовку доступной каждому, в любое время и по честной цене.\n\nПопробуйте сами — задайте наставнику любой вопрос по физике или математике голосом. Скорее всего, вы удивитесь, насколько по-человечески звучит ответ.',
  'education',
